import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import Footer from '../components/Footer';
import ProductCard from '../components/ProductCard';
import API from '../api/axios';
import './Shop.css';

const SORT_OPTIONS = [
  { label: 'Featured',        value: '-created_at' },
  { label: 'Price: Low–High', value: 'price' },
  { label: 'Price: High–Low', value: '-price' },
  { label: 'Name: A–Z',       value: 'name' },
];

export default function Shop({ category }) {
  const [products, setProducts] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [sort, setSort]         = useState('-created_at');
  const [search, setSearch]     = useState('');
  const [page, setPage]         = useState(1);
  const [hasNext, setHasNext]   = useState(false);
  const [count, setCount]       = useState(0);
  const navigate = useNavigate();

  const title = category === 'lingerie' ? 'Lingerie Collection' : 'Swimwear Collection';

  const fetchProducts = useCallback(() => {
    setLoading(true);
    const params = new URLSearchParams({
      'category__slug': category,
      ordering: sort,
      page,
    });
    if (search) params.append('search', search);

    API.get(`/products/?${params}`)
      .then(({ data }) => {
        setProducts(data.results || data);
        setHasNext(!!data.next);
        setCount(data.count || (data.results || data).length);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [category, sort, search, page]);

  useEffect(() => {
    setPage(1);
    setProducts([]);
  }, [category, sort, search]);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  return (
    <>
      <Header />

      {/* Breadcrumb */}
      <div className="breadcrumb">
        <span className="bc" onClick={() => navigate('/')}>Home</span>
        <span className="bc-sep">›</span>
        <span className="bc cur">{title}</span>
      </div>

      <main className="shop-page">
        {/* Header bar */}
        <div className="shop-page__header">
          <div>
            <h1 className="shop-page__title">{title}</h1>
            <p className="shop-page__count">{count} pieces</p>
          </div>
          <div className="shop-page__toolbar">
            <div className="shop-search">
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
              </svg>
              <input
                type="text"
                placeholder="Search..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="shop-search__input"
              />
            </div>
            <div className="sort-wrap">
              <span className="sort-lbl">Sort</span>
              <select
                className="sort-sel"
                value={sort}
                onChange={(e) => setSort(e.target.value)}
              >
                {SORT_OPTIONS.map((o) => (
                  <option key={o.value} value={o.value}>{o.label}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Grid */}
        {loading && products.length === 0 ? (
          <div className="spinner-wrap"><div className="spinner" /></div>
        ) : products.length === 0 ? (
          <div className="shop-empty">
            <p>No products found{search ? ` for "${search}"` : ''}.</p>
            {search && <button className="btn-ghost" onClick={() => setSearch('')}>Clear search</button>}
          </div>
        ) : (
          <div className="shop-page__grid">
            {products.map((p) => <ProductCard key={p.id} product={p} />)}
          </div>
        )}

        {/* Pagination */}
        {(hasNext || page > 1) && (
          <div className="shop-pagination">
            {page > 1 && (
              <button className="btn-ghost" onClick={() => setPage((p) => p - 1)}>← Previous</button>
            )}
            {hasNext && (
              <button className="btn-primary" onClick={() => setPage((p) => p + 1)}>
                {loading ? 'Loading…' : 'Load More'}
              </button>
            )}
          </div>
        )}
      </main>

      <Footer />
    </>
  );
}
